import '../../fonts/Montserrat-Regular.otf';

import {
	Box,
	Icon,
	IconButton,
	LinearProgress,
	Typography,
	makeStyles,
	TextField,
} from '@material-ui/core';
import React, { useEffect, useState } from 'react';
import { generatePath, useHistory } from 'react-router';
import { loadListaPreConta, postAuthMeAction } from '../../actions/actions';
import { useDispatch, useSelector } from 'react-redux';

import CheckIcon from '@material-ui/icons/Check';
import ClearIcon from '@material-ui/icons/Clear';
import CustomTable from '../../components/CustomTable/CustomTable';
import CustomTextField from '../../components/CustomTextField/CustomTextField';
import { Pagination } from '@material-ui/lab';
import RefreshIcon from '@material-ui/icons/Refresh';
import useAuth from '../../hooks/useAuth';
import useDebounce from '../../hooks/useDebounce';

const useStyles = makeStyles(() => ({
	root: {
		display: 'flex',
		flexDirection: 'column',
	},
	headerContainer: {
		display: 'flex',
		flexDirection: 'column',
		justifyContent: 'space-between',
		marginBottom: '0px',
	},
	tableContainer: { marginTop: '1px' },
	pageTitle: {
		color: '#9D9CC6',
		fontFamily: 'Montserrat-Regular',
	},
}));

const columns = [
	{
		headerText: 'Nome',
		key: 'nome',
		CustomValue: (value) => <Typography>{value}</Typography>,
	},
	{
		headerText: 'Documento',
		key: 'documento',
		CustomValue: (value) => {
			return (
				<Typography style={{ color: value ? '#4C4B97' : 'red' }}>
					{value ? value : 'Não cadastrado'}
				</Typography>
			);
		},
	},
	{
		headerText: 'Contato',
		key: '',
		FullObject: ({ verifica_contato }) => {
			return verifica_contato ? (
				<Typography
					style={{ color: verifica_contato.celular ? '#4C4B97' : 'red' }}
				>
					{verifica_contato.celular
						? verifica_contato.celular
						: 'Não cadastrado'}
				</Typography>
			) : (
				<Typography style={{ color: 'red' }}>Não Cadastrado</Typography>
			);
		},
	},
	{
		headerText: 'E-mail',
		key: '',
		FullObject: ({ verifica_contato }) => {
			return verifica_contato ? (
				<Typography
					style={{ color: verifica_contato.email ? '#4C4B97' : 'red' }}
				>
					{verifica_contato.email
						? verifica_contato.email
						: 'Não cadastrado'}
				</Typography>
			) : (
				<Typography style={{ color: 'red' }}>Não Cadastrado</Typography>
			);
		},
	},
	{
		headerText: 'Verificado',
		key: '',
		FullObject: ({ verifica_contato }) => {
			return verifica_contato ? (
				<Box
					style={{
						display: 'flex',
						justifyContent: 'center',
						alignItems: 'center',
					}}
				>
					<Typography
						style={{
							color: verifica_contato.email_verificado ? 'green' : 'red',
						}}
					>
						Email
					</Typography>
					{verifica_contato.email_verificado ? (
						<CheckIcon style={{ marginLeft: 5, color: 'green' }} />
					) : (
						<ClearIcon style={{ marginLeft: 5, color: 'red' }} />
					)}
					<Typography
						style={{
							color: verifica_contato.celular_verificado
								? 'green'
								: 'red',
						}}
					>
						Celular
					</Typography>
					{verifica_contato.celular_verificado ? (
						<CheckIcon style={{ marginLeft: 5, color: 'green' }} />
					) : (
						<ClearIcon style={{ marginLeft: 5, color: 'red' }} />
					)}
				</Box>
			) : (
				<Box
					style={{
						display: 'flex',
						justifyContent: 'center',
						alignItems: 'center',
					}}
				>
					<Typography style={{ color: 'red' }}>Email</Typography>
					<ClearIcon style={{ marginLeft: 5, color: 'red' }} />
					<Typography style={{ color: 'red' }}>Celular</Typography>
					<ClearIcon style={{ marginLeft: 5, color: 'red' }} />
				</Box>
			);
		},
	},
];

const GerenciarListaPreContas = () => {
	const token = useAuth();
	const classes = useStyles();
	const dispatch = useDispatch();
	const listaContas = useSelector((state) => state.listaPreContas);
	const history = useHistory();
	const [page, setPage] = useState(1);

	const [filters, setFilters] = useState({
		like: '',
		order: '',
		mostrar: '',
	});
	const debouncedLike = useDebounce(filters.like, 800);

	const handleChangePage = (e, value) => {
		setPage(value);
	};

	useEffect(() => {
		dispatch(
			loadListaPreConta(
				token,
				page,
				debouncedLike,
				filters.order,
				filters.mostrar
			)
		);
	}, [page, debouncedLike, filters.order, filters.mostrar]);

	const handleClickRow = (row) => {
		const path = generatePath('/dashboard/detalhes-pre-conta/:id/ver', {
			id: row.id,
		});
		history.push(path);
	};

	return (
		<Box className={classes.root}>
			<Box className={classes.headerContainer}>
				<Box style={{ marginBottom: '20px' }}>
					<Typography className={classes.pageTitle}>Pré Contas</Typography>
				</Box>
				<Box
					style={{
						width: '100%',
						backgroundColor: '#EFEFF6',
						borderTopLeftRadius: 27,
						borderTopRightRadius: 27,
					}}
				>
					<Box
						display="flex"
						justifyContent="space-between"
						alignItems="center"
						style={{ margin: 30 }}
					>
						<TextField
							placeholder="Pesquisar por nome, documento, email..."
							size="small"
							variant="outlined"
							style={{
								backgroundColor: '#ECECF4',
								width: '400px',
							}}
							onChange={(e) => {
								setPage(1);
								setFilters({
									...filters,
									like: e.target.value,
								});
							}}
						></TextField>
					</Box>
				</Box>
			</Box>

			<Box className={classes.tableContainer}>
				{listaContas.data && listaContas.per_page ? (
					<CustomTable
						columns={columns ? columns : null}
						data={listaContas.data}
						handleClickRow={handleClickRow}
					/>
				) : (
					<Box width="60vw">
						<LinearProgress color="secondary" />
					</Box>
				)}
				<Box
					display="flex"
					alignSelf="flex-end"
					marginTop="8px"
					justifyContent="space-between"
				>
					<Pagination
						variant="outlined"
						color="secondary"
						size="large"
						count={listaContas.last_page}
						onChange={handleChangePage}
						page={page}
					/>
					<IconButton
						style={{
							backgroundColor: 'white',
							boxShadow: '0px 0px 5px 0.7px grey',
						}}
						onClick={() => window.location.reload(false)}
					>
						<RefreshIcon />
					</IconButton>
				</Box>
			</Box>
		</Box>
	);
};

export default GerenciarListaPreContas;
