import { Query } from '../helpers/cogent-js';
import axios from 'axios';

export const getContas = (
	token,
	page,
	like,
	order,
	mostrar,
	id,
	seller,
	status,
	numero_documento,
	tipo
) => {
	const url = `${process.env.REACT_APP_API_URL}/contas?
	page=${page}
	&like=${like}
	&order=${order}
	&mostrar=${mostrar}
	&id=${id}
	&seller=${seller}
	&status=${status}
	&numero_documento=${numero_documento}
	&tipo=${tipo}`;

	return axios({
		method: 'get',
		url,
		headers: {
			Authorization: `Bearer ${token}`,
		},
	});
};

