export const getContasAction =
	(
		token,
		page,
		like,
		order,
		mostrar,
		id,
		seller,
		status,
		numero_documento,
		tipo
	) =>
	async (dispatch) => {
		try {
			const res = await getContas(
				token,
				page,
				like,
				order,
				mostrar,
				id,
				seller,
				status,
				numero_documento,
				tipo
			);
			dispatch({
				type: LOAD_CONTAS,
				payload: res.data,
			});
			return true;
		} catch (err) {
			console.log(err);
			return false;
		}
	};

