export const updateConta = (token, conta, id) => async (dispatch) => {
	try {
		const res = await putConta(token, conta, id);
		dispatch({
			type: POST_CONTA,
			payload: res.data,
		});
	} catch (err) {
		console.log(err);
		if (err.response.status === 422) {
			return err.response.data.errors;
		} else {
			toast.error('Erro no cadastro');
			return err;
		}
	}
};

