import { Grid, Paper, useTheme, TextField } from '@material-ui/core';
import React, { useState } from 'react';

import Avatar from '@material-ui/core/Avatar';
import Box from '@material-ui/core/Box';
import Button from '@material-ui/core/Button';
import CustomTextField from '../../components/CustomTextField/CustomTextField';
import ItaDash1 from '../../assets/ItaDash1.svg';

import Typography from '@material-ui/core/Typography';
import { makeStyles } from '@material-ui/styles';
import { postPrimeiroAcesso } from '../../actions/actions';
import { toast } from 'react-toastify';
import { useDispatch } from 'react-redux';
import { useHistory } from 'react-router';
import vBankLogo from '../../assets/vbankSvgs/vBankLogo.svg';

const useStyles = makeStyles((theme) => ({
	root: {
		display: 'flex',
		background:
			'linear-gradient(135deg, rgba(2,149,59,1) 15%, rgba(75,75,150,1) 100%)',
		margin: '0px',
		padding: '0px',
		[theme.breakpoints.down('sm')]: {
			flexDirection: 'column-reverse',
		},
	},

	rightSide: {
		display: 'flex',
		flexDirection: 'column',
		alignItems: 'center',
		width: '55%',
		height: '100vh',

		color: '#35322f',
		[theme.breakpoints.down('sm')]: {
			width: '100vw',
			height: '100vh',
		},
	},
	leftSideText: {},
	leftSide: {
		display: 'flex',
		justifyContent: 'center',
		width: '45%',

		padding: '80px',
		[theme.breakpoints.down('sm')]: {
			width: '100vw',
			height: '100vh',
			padding: '0px',
		},
	},

	paper: {
		backgroundColor: '#EDEDF4',
		marginTop: theme.spacing(8),
		display: 'flex',
		flexDirection: 'column',
		height: '600px',
		alignItems: 'center',
		padding: '40px',
		width: '60%',
		borderRadius: '27px',
		animation: `$myEffect 1000ms ${theme.transitions.easing.easeInOut}`,
		[theme.breakpoints.down('sm')]: {
			width: '100%',
		},
	},
	avatar: {
		margin: theme.spacing(1),
		backgroundColor: '#4C4B97',
		color: 'white',
	},
	form: {
		width: '100%',
		marginTop: theme.spacing(1),
	},
	submit: {
		margin: theme.spacing(3, 0, 2),
	},

	'@keyframes myEffect': {
		'0%': {
			opacity: 0,
			transform: 'translateX(-10%)',
		},
		'100%': {
			opacity: 1,
			transform: 'translateX(0)',
		},
	},
}));

const Cadastro = () => {
	const classes = useStyles();
	const [user, setUser] = useState({
		email: '',
		token: '',
		password: '',
		password_confirmation: '',
	});
	const theme = useTheme();
	const [errosUser, setErrosUser] = useState({});
	const history = useHistory();
	const [, setLoading] = useState(false);
	const dispatch = useDispatch();
	const onCadastrar = async () => {
		setLoading(true);
		let newUser = user;
		const resUser = await dispatch(postPrimeiroAcesso(newUser));
		if (resUser) {
			setErrosUser(resUser);
			setLoading(false);
		} else {
			toast.success(
				'Cadastro efetuado com sucesso, faça login para ter acesso!'
			);
			history.push('/login');
			setLoading(false);
		}
	};

	return (
		<>
			<Box className={classes.root}>
				<Box className={classes.leftSide}>
					<Paper className={classes.paper}>
						<Avatar className={classes.avatar} />
						<Typography
							component="h1"
							variant="h5"
							style={{ marginBottom: '4px' }}
						>
							Cadastrar
						</Typography>

						<Grid container spacing={5} className={classes.form}>
							<Grid item xs={12}>
								<TextField
									variant="outlined"
									error={errosUser.token}
									helperText={
										errosUser.token ? errosUser.token.join(' ') : null
									}
									autoFocus
									label="Código de verificação enviado por e-mail"
									fullWidth
									required
									value={user.token}
									onChange={(e) =>
										setUser({ ...user, token: e.target.value })
									}
								/>
							</Grid>
							<Grid item xs={12}>
								<TextField
									variant="outlined"
									error={errosUser.email}
									helperText={
										errosUser.email ? errosUser.email.join(' ') : null
									}
									type="email"
									fullWidth
									label="Digite seu email"
									name="email"
									value={user.email}
									onChange={(e) =>
										setUser({ ...user, email: e.target.value })
									}
									required
								/>
							</Grid>
							<Grid item xs={12}>
								<TextField
									variant="outlined"
									error={errosUser.password}
									helperText={
										errosUser.password
											? errosUser.password.join(' ')
											: null
									}
									type="password"
									required
									fullWidth
									name="password"
									label="Digite sua senha"
									id="password"
									autoComplete="current-password"
									value={user.password}
									onChange={(e) =>
										setUser({ ...user, password: e.target.value })
									}
								/>
							</Grid>
							<Grid item xs={12}>
								<TextField
									variant="outlined"
									error={errosUser.password_confirmation}
									helperText={
										errosUser.password_confirmation
											? errosUser.password_confirmation.join(' ')
											: null
									}
									type="password"
									required
									fullWidth
									name="password"
									label="Confirmação de senha"
									id="password"
									autoComplete="current-password"
									value={user.password_confirmation}
									onChange={(e) =>
										setUser({
											...user,
											password_confirmation: e.target.value,
										})
									}
								/>
							</Grid>
							<Button
								size="large"
								fullWidth
								variant="contained"
								className={classes.submit}
								style={{
									borderRadius: '27px',
									backgroundColor: '#4C4B97',
									fontFamily: 'Montserrat-Regular',
								}}
								onClick={onCadastrar}
							>
								Cadastrar
							</Button>
						</Grid>
					</Paper>
				</Box>
				<Box className={classes.rightSide}>
					<Box>
						<img
							style={{
								width: '200px',
								justifySelf: 'flex-start',
								marginTop: '100px',
							}}
							src={vBankLogo}
							alt="Itapemirim logo"
						/>
					</Box>
					<Box
						display="flex"
						flexDirection="column"
						alignItems="center"
						marginTop="150px"
					>
						<Typography
							variant="h3"
							align="center"
							style={{ color: 'white' }}
						>
							Primero acesso?
						</Typography>
						<Typography
							align="center"
							variant="h6"
							style={{ fontWeight: '100', color: 'white' }}
						>
							Bem-vindo! Falta pouco para finalizar seu cadastro.
						</Typography>
						<Typography
							align="center"
							variant="h6"
							style={{ fontWeight: '100', color: 'white' }}
						>
							Basta inserir o código enviado via EMAIL e preencher os
							campos.
						</Typography>
					</Box>
				</Box>
			</Box>
		</>
	);
};

export default Cadastro;
