import {
	Box,
	Button,
	Grid,
	IconButton,
	InputLabel,
	LinearProgress,
	MenuItem,
	Select,
	TextField,
	Tooltip,
	Typography,
	useMediaQuery,
	useTheme,
} from '@material-ui/core';
import React, { useEffect, useMemo, useState } from 'react';
import { faTable, faTrash } from '@fortawesome/free-solid-svg-icons';
import { generatePath, useHistory, useParams } from 'react-router';
import {
	loadExportPartnerTransactions,
	loadPartnerTransactions,
} from '../../actions/actions';
import { useDispatch, useSelector } from 'react-redux';
import CurrencyTextField from '@unicef/material-ui-currency-textfield';

import CustomBreadcrumbs from '../../components/CustomBreadcrumbs/CustomBreadcrumbs';
/* import CustomTable from '../../components/CustomTablePartner/CustomTable'; */
import CustomTable from '../../components/CustomTable/CustomTable';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import LoadingScreen from '../../components/LoadingScreen/LoadingScreen';
import Pagination from '@material-ui/lab/Pagination';
import columns from './JeittoTransactionsColumns';
import { toast } from 'react-toastify';
import useAuth from '../../hooks/useAuth';
import useDebounce from '../../hooks/useDebounce';
import RefreshIcon from '@material-ui/icons/Refresh';

const JeittoAdm = () => {
	const token = useAuth();
	const dispatch = useDispatch();
	const [page, setPage] = useState(1);
	const history = useHistory();
	const historico = useSelector((state) => state.partnerTransactions);
	const exportTransacao = useSelector((state) => state.exportTransacao);
	const userData = useSelector((state) => state.userData);
	const { id } = useParams();

	const handleChangePage = (e, value) => {
		setPage(value);
	};

	const [filters, setFilters] = useState({
		day: '',
		order: ' ',
		mostrar: ' ',
		status: ' ',
		cpf: '',
		nsu_transaction: ' ',
		email: '',
		name: '',
		ddd_phone: '',
		value: '',
		expiration_date_start: '',
		expiration_date_end: '',
		created_at_between_start: '',
		created_at_between_end: '',
		value_start: '',
		value_end: '',
		agency_code: '',
	});
	const debouncedName = useDebounce(filters.name, 800);
	const debouncedAgencyCode = useDebounce(filters.agency_code, 800);
	const theme = useTheme();
	const matches = useMediaQuery(theme.breakpoints.down('sm'));

	useEffect(() => {
		dispatch(
			loadPartnerTransactions(
				token,
				page,
				filters.order,
				filters.status,
				filters.mostrar,
				filters.cpf,
				filters.expiration_date_start,
				filters.expiration_date_end,
				filters.created_at_between_start,
				filters.created_at_between_end,
				filters.nsu_transaction,
				filters.email,
				debouncedName,
				filters.ddd_phone,
				filters.value_start,
				filters.value_end,
				debouncedAgencyCode
			)
		);
	}, [
		debouncedAgencyCode,
		debouncedName,
		dispatch,
		filters.cpf,
		filters.created_at_between_end,
		filters.created_at_between_start,
		filters.ddd_phone,
		filters.email,
		filters.expiration_date_end,
		filters.expiration_date_start,
		filters.mostrar,
		filters.nsu_transaction,
		filters.order,
		filters.status,
		filters.value_end,
		filters.value_start,
		page,
		token,
	]);

	useEffect(() => {
		return () => {
			setFilters({ ...filters });
		};
	}, []);

	const [loading, setLoading] = useState(false);

	const handleExportarTransacao = async () => {
		setLoading(true);
		toast.warning('A exportação pode demorar um pouco, por favor aguarde...');
		const res = await dispatch(
			loadExportPartnerTransactions(
				token,
				page,
				filters.order,
				filters.status,
				filters.mostrar,
				filters.cpf,
				filters.expiration_date_start,
				filters.expiration_date_end,
				filters.created_at_between_start,
				filters.created_at_between_end,
				filters.nsu_transaction,
				filters.email,
				filters.name,
				filters.ddd_phone,
				filters.value_start,
				filters.value_end,
				filters.agency_code
			)
		);
		if (res && res.url !== undefined) {
			window.open(`${res.url}`, '', '');
		}
		setLoading(false);
	};

	const rows = useMemo(() => {
		return historico.data;
	}, [historico]);

	return (
		<Box display="flex" flexDirection="column" style={{ marginBottom: 30 }}>
			<LoadingScreen isLoading={loading} />
			{token && userData === '' ? (
				<CustomBreadcrumbs
					path1="Parceiros"
					to1="/dashboard/partners"
					path2="Transações Jeitto"
				/>
			) : (
				<CustomBreadcrumbs
					path1="Parceiros"
					to1="/dashboard/partners"
					path2="Transações Jeitto"
				/>
			)}
			<Box display="flex" justifyContent="">
				<Typography
					style={{ marginTop: '8px', color: '#9D9CC6', marginBottom: 30 }}
					variant="h4"
				>
					Transações Jeitto
				</Typography>
			</Box>
			<Box
				style={{
					width: '100%',
					backgroundColor: '#EFEFF6',
					borderTopLeftRadius: 27,
					borderTopRightRadius: 27,
				}}
			>
				<Box
					style={{
						margin: 30,
						padding: '15px',
						/* backgroundColor: 'green', */
					}}
					display="flex"
				>
					<Grid container spacing={3}>
						<Grid item xs={12} sm={3}>
							<TextField
								variant="outlined"
								InputLabelProps={{
									shrink: true,
								}}
								placeholder="Filtrar pelo nome"
								fullWidth
								label="Nome"
								value={filters.name}
								onChange={(e) =>
									setFilters({ ...filters, name: e.target.value })
								}
							/>
						</Grid>
						<Grid item xs={12} sm={3}>
							<TextField
								variant="outlined"
								InputLabelProps={{
									shrink: true,
								}}
								placeholder="Filtrar por cpf"
								fullWidth
								label="CPF"
								value={filters.cpf}
								onChange={(e) =>
									setFilters({ ...filters, cpf: e.target.value })
								}
							/>
						</Grid>
						<Grid item xs={12} sm={3}>
							<TextField
								variant="outlined"
								InputLabelProps={{
									shrink: true,
								}}
								placeholder="Filtrar por email"
								fullWidth
								label="Email"
								value={filters.email}
								onChange={(e) =>
									setFilters({ ...filters, email: e.target.value })
								}
							/>
						</Grid>
						<Grid item xs={12} sm={3}>
							<TextField
								variant="outlined"
								InputLabelProps={{
									shrink: true,
								}}
								placeholder="Filtrar por cpf"
								fullWidth
								label="NSU da transação"
								value={filters.nsu_transaction}
								onChange={(e) =>
									setFilters({
										...filters,
										nsu_transaction: e.target.value,
									})
								}
							/>
						</Grid>
						<Grid item xs={12} sm={2}>
							<Select
								style={{ marginTop: '10px', color: '#9D9DC6' }}
								variant="outlined"
								fullWidth
								value={filters.status}
								onChange={(e) =>
									setFilters({ ...filters, status: e.target.value })
								}
							>
								<MenuItem value={' '} style={{ color: '#9D9DC6' }}>
									Status
								</MenuItem>
								<MenuItem value={'0'} style={{ color: '#9D9DC6' }}>
									Pendente
								</MenuItem>
								<MenuItem value={'1'} style={{ color: '#9D9DC6' }}>
									Expirada
								</MenuItem>
								<MenuItem value={'2'} style={{ color: '#9D9DC6' }}>
									Confirmada
								</MenuItem>
								<MenuItem value={'3'} style={{ color: '#9D9DC6' }}>
									Sem limite
								</MenuItem>
								<MenuItem value={'4'} style={{ color: '#9D9DC6' }}>
									Erro
								</MenuItem>
								<MenuItem value={'5'} style={{ color: '#9D9DC6' }}>
									Sem limite POS/PRE
								</MenuItem>
								<MenuItem value={'6'} style={{ color: '#9D9DC6' }}>
									Valor não alcançado
								</MenuItem>
								<MenuItem value={'7'} style={{ color: '#9D9DC6' }}>
									Limite bloqueado
								</MenuItem>
								<MenuItem value={'8'} style={{ color: '#9D9DC6' }}>
									Negado
								</MenuItem>
							</Select>
						</Grid>
						<Grid item xs={12} sm={3}>
							<TextField
								variant="outlined"
								fullWidth
								InputLabelProps={{
									shrink: true,
									pattern: 'd {4}- d {2}- d {2} ',
								}}
								type="date"
								label="Data de criação inicial"
								value={filters.created_at_between_start}
								onChange={(e) =>
									setFilters({
										...filters,
										created_at_between_start: e.target.value,
									})
								}
							/>
						</Grid>
						<Grid item xs={12} sm={3}>
							<TextField
								variant="outlined"
								fullWidth
								InputLabelProps={{
									color: '#9D9DC6',
									shrink: true,
									pattern: 'd {4}- d {2}- d {2} ',
								}}
								type="date"
								label="Data de criação final"
								value={filters.created_at_between_end}
								onChange={(e) =>
									setFilters({
										...filters,
										created_at_between_end: e.target.value,
									})
								}
							/>
						</Grid>

						<Grid item xs={12} sm={2}>
							<TextField
								variant="outlined"
								fullWidth
								InputLabelProps={{
									shrink: true,
									pattern: 'd {4}- d {2}- d {2} ',
								}}
								type="date"
								label="Data de expiração Inicial"
								value={filters.expiration_date_start}
								onChange={(e) =>
									setFilters({
										...filters,
										expiration_date_start: e.target.value,
									})
								}
							/>
						</Grid>
						<Grid item xs={12} sm={2}>
							<TextField
								variant="outlined"
								fullWidth
								InputLabelProps={{
									shrink: true,
									pattern: 'd {4}- d {2}- d {2} ',
								}}
								type="date"
								label="Data de expiração Final"
								value={filters.expiration_date_end}
								onChange={(e) =>
									setFilters({
										...filters,
										expiration_date_end: e.target.value,
									})
								}
							/>
						</Grid>

						<Grid item xs={12} sm={2}>
							<CurrencyTextField
								variant="outlined"
								decimalPlacesShownOnFocus={0}
								currencySymbol="R$"
								maximumValue={100000}
								minimumValue={0}
								label="Valor inicial"
								decimalCharacter=","
								digitGroupSeparator="."
								value={filters.value_start}
								onChange={(e) =>
									setFilters({
										...filters,
										value_start: e.target.value
											.replace('.', '')
											.replace(',', '.'),
									})
								}
							/>
						</Grid>
						<Grid item xs={12} sm={2}>
							<CurrencyTextField
								variant="outlined"
								decimalPlacesShownOnFocus={0}
								currencySymbol="R$"
								maximumValue={100000}
								minimumValue={0}
								label="Valor Final"
								decimalCharacter=","
								digitGroupSeparator="."
								value={filters.value_end}
								onChange={(e) =>
									setFilters({
										...filters,
										value_end: e.target.value
											.replace('.', '')
											.replace(',', '.'),
									})
								}
							/>
						</Grid>

						<Grid item xs={12} sm={3}>
							<TextField
								variant="outlined"
								InputLabelProps={{
									shrink: true,
								}}
								placeholder="Filtrar pelo código"
								fullWidth
								label="Código Agência"
								value={filters.agency_code}
								onChange={(e) =>
									setFilters({
										...filters,
										agency_code: e.target.value,
									})
								}
							/>
						</Grid>

						<Grid item xs={12} sm={4}>
							<Box display="flex" width="100%" justifyContent="flex-end">
								<Tooltip title="Limpar Filtros">
									<IconButton
										onClick={() =>
											setFilters({
												...filters,
												day: '',
												order: ' ',
												mostrar: ' ',
												status: ' ',
												cpf: '',
												nsu_transaction: ' ',
												email: '',
												name: '',
												ddd_phone: '',
												value_start: '',
												value_end: '',
												expiration_date_start: '',
												expiration_date_end: '',
												created_at_between_start: '',
												created_at_between_end: '',
											})
										}
									>
										<FontAwesomeIcon icon={faTrash} />
									</IconButton>
								</Tooltip>
								<Tooltip title="Exportar Excel">
									<IconButton
										variant="outlined"
										style={{ marginLeft: '6px' }}
										onClick={handleExportarTransacao}
									>
										<FontAwesomeIcon icon={faTable} color="green" />
									</IconButton>
								</Tooltip>
							</Box>
						</Grid>
					</Grid>
				</Box>
			</Box>
			<Box style={{ marginTop: '1px' }}>
				{historico.data && historico.per_page ? (
					<Box minWidth={!matches ? '800px' : null}>
						<CustomTable
							columns={columns}
							data={rows}
							/* handleClickRow={handleClickRow} */
						/>
					</Box>
				) : (
					<Box width="60vw">
						<LinearProgress color="secondary" />
					</Box>
				)}

				<Box
					display="flex"
					alignSelf="flex-end"
					marginTop="8px"
					justifyContent="space-between"
				>
					<Pagination
						variant="outlined"
						color="secondary"
						size="large"
						count={historico.last_page}
						onChange={handleChangePage}
						page={page}
					/>
					<IconButton
						style={{
							backgroundColor: 'white',
							boxShadow: '0px 0px 5px 0.7px grey',
						}}
						onClick={() => window.location.reload(false)}
					>
						<RefreshIcon></RefreshIcon>
					</IconButton>
				</Box>
			</Box>
		</Box>
	);
};

export default JeittoAdm;
